ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?tool_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:tool_name ?cg . ?child a :Tools ; p:tool_name ?cg . ?l p:designer_id ?pg . ?parent a :Designers ; p:id ?pg . } GROUP BY ?child }
  ?child p:tool_name ?tool_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Designers } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?tool_name WHERE {
  ?designer_tools a :Designer_Tools .
  ?tools a :Tools .
  ?designer_tools p:hasTools ?tools .
  ?designers a :Designers .
  ?designer_tools p:hasDesigners ?designers .
  ?designers p:name ?name .
  ?tools p:tool_name ?tool_name .
} }
}

